import { Component } from '@angular/core';
import { InventoryItem } from '../../models/inventory-item.model';
import { InventoryService } from '../../services/inventory.service';

@Component({
  selector: 'app-search-items',
  templateUrl: './search-items.component.html'
})
export class SearchItemsComponent {
  query = '';
  filtered: InventoryItem[] = [];
  message = 'Search items by name or display all/popular items.';

  constructor(private readonly inventoryService: InventoryService) {
    this.showAll();
  }

  search(): void {
    const input: string = this.query.trim();
    if (!input) {
      this.message = 'Enter text to search by item name.';
      return;
    }
    this.filtered = this.inventoryService.searchByName(input);
    this.message = `Found ${this.filtered.length} item(s) for '${input}'.`;
  }

  showAll(): void {
    this.filtered = this.inventoryService.getAllItems();
    this.message = `Showing all ${this.filtered.length} item(s).`;
  }

  showPopular(): void {
    this.filtered = this.inventoryService.getPopularItems();
    this.message = `Showing ${this.filtered.length} popular item(s).`;
  }
}
<section class="page">
  <h2>Search and Filter Items</h2>

  <div class="row">
    <input [(ngModel)]="query" type="text" placeholder="Search by item name">
    <button type="button" (click)="search()">Search</button>
    <button type="button" (click)="showAll()" class="secondary">Show All</button>
    <button type="button" (click)="showPopular()">Show Popular</button>
  </div>

  <div class="message">{{ message }}</div>

  <table>
    <thead>
      <tr>
        <th>ID</th>
        <th>Name</th>
        <th>Category</th>
        <th>Qty</th>
        <th>Price</th>
        <th>Supplier</th>
        <th>Stock</th>
        <th>Popular</th>
        <th>Comment</th>
      </tr>
    </thead>
    <tbody>
      <tr *ngFor="let item of filtered">
        <td>{{ item.id }}</td>
        <td>{{ item.name }}</td>
        <td>{{ item.category }}</td>
        <td>{{ item.quantity }}</td>
        <td>{{ item.price | number: '1.2-2' }}</td>
        <td>{{ item.supplier }}</td>
        <td>{{ item.stockStatus }}</td>
        <td>{{ item.popular ? 'Yes' : 'No' }}</td>
        <td>{{ item.comment || '' }}</td>
      </tr>
    </tbody>
  </table>
</section>
